import json
from typing import Union


def flatten_ec2_metadata(data: Union[dict, str], max_depth: int = 20) -> dict:
    """
    Convert AWS EC2 instance metadata JSON response into a flattened dictionary with dot-notation keys.

    Parameters:
        data (dict or str): The input metadata as a pre-parsed dict or a raw JSON string.
        max_depth (int): Maximum nesting depth allowed, defaulting to 20. The root dict is
            processed at depth=0 (first level of keys), depth=1 represents the second level,
            and so on. A ValueError is raised when depth reaches max_depth, meaning exactly
            20 levels of nesting are permitted (depth 0 through 19).

    Returns:
        dict: A flat dictionary where nested keys are joined with dot-notation
            (e.g., 'network.interfaces.0.mac'). If the root value is not a dict,
            returns {"" : <scalar_value>}.

    Raises:
        ValueError: If input is None or not a dict or str type.
        ValueError: If a JSON string input cannot be parsed by json.loads().
        ValueError: If depth >= max_depth during recursion, indicating nesting is too deep.

    Examples:
        >>> metadata = {"instanceId": "i-1234", "network": {"mac": "0a:1b"}}
        >>> flatten_ec2_metadata(metadata, max_depth=20)
        {'instanceId': 'i-1234', 'network.mac': '0a:1b'}

        >>> deep = {"a": {"b": {"c": {"d": {"e": {"f": {"g": {"h": {"i": {"j": {"k": {"l": {"m": {"n": {"o": {"p": {"q": {"r": {"s": {"t": "v"}}}}}}}}}}}}}}}}}}}}}}
        >>> flatten_ec2_metadata(deep, max_depth=5)
        Traceback (most recent call last):
            ...
        ValueError: Maximum recursion depth of 5 reached at depth 5.
    """
    if data is None or not isinstance(data, (dict, str)):
        raise ValueError(f"Input must be a dict or str, got {type(data).__name__}.")

    if isinstance(data, str):
        try:
            data = json.loads(data)
        except json.JSONDecodeError as e:
            raise ValueError(f"Failed to parse JSON string: {e}")

    if not isinstance(data, dict):
        return {"": data}

    def _flatten(obj: dict, prefix: str, depth: int) -> dict:
        if depth >= max_depth:
            raise ValueError(f"Maximum recursion depth of {max_depth} reached at depth {depth}.")
        result = {}
        for key, value in obj.items():
            full_key = prefix + "." + key if prefix else key
            if isinstance(value, dict):
                result.update(_flatten(value, full_key, depth + 1))
            elif isinstance(value, list):
                for i, item in enumerate(value):
                    indexed_key = full_key + "." + str(i)
                    if isinstance(item, dict):
                        result.update(_flatten(item, indexed_key, depth + 1))
                    else:
                        result[indexed_key] = item
            else:
                result[full_key] = value
        return result

    return _flatten(data, "", 0)

