from typing import List, Dict, Any


def _extract_value(typed_value: Dict[str, Any]) -> Any:
    """Extract plain Python value from DynamoDB typed value dict."""
    if 'S' in typed_value:
        return typed_value['S']
    elif 'N' in typed_value:
        return typed_value['N']
    elif 'BOOL' in typed_value:
        return typed_value['BOOL']
    else:
        raise ValueError(f"Unsupported DynamoDB type key in: {typed_value}")


def filter_dynamodb_items(
    items: List[Dict[str, Any]],
    attribute_name: str,
    condition_value: Any
) -> List[Dict[str, Any]]:
    """
    Filter DynamoDB items based on a simple attribute condition.

    Parameters:
        items: List of item dicts in DynamoDB boto3 typed format.
        attribute_name: The attribute name to filter on.
        condition_value: The value to compare against. For N type attributes,
            condition_value may be either a number or a numeric string and will
            be coerced to float for comparison using float(stored) == float(condition_value).

    Returns:
        List of items where the attribute matches condition_value.

    Raises:
        ValueError: If items is None or contains non-dict elements.
        ValueError: If attribute_name is not a string or is empty.
        ValueError: If an unsupported DynamoDB type key is encountered.
    """
    if not isinstance(attribute_name, str):
        raise ValueError("attribute_name must be a string")
    if attribute_name == '':
        raise ValueError("attribute_name must not be empty")
    if items is None:
        raise ValueError("items must not be None")
    if not all(isinstance(item, dict) for item in items):
        raise ValueError("All elements in items must be dicts")

    result = []
    for item in items:
        if attribute_name not in item:
            continue
        typed_val = item[attribute_name]
        type_key = next(iter(typed_val))
        raw = _extract_value(typed_val)
        if type_key == 'N':
            match = float(raw) == float(condition_value)
        else:
            match = raw == condition_value
        if match:
            result.append(item)
    return result
